@ARTICLE{10.1186/s12879-026-12822-9,
	author = {Wang P and Tian B and Tian C and Shan C and Huang R and Zhang Q},
	title = {Clinical characteristics and prognosis of patients with Chlamydia psittaci pneumonia identified by metagenomic next-generation sequencing.},
	journal = {BMC Infect Dis},
	year = {2026},
	abstract = {BACKGROUND: Few studies comprehensively reported the clinical characteristics, prognosis, and factors associated with severe disease in patients with confirmed Chlamydia psittaci pneumonia identified by metagenomic next-generation sequencing (mNGS). METHODS: This retrospective study included 63 patients with Chlamydia psittaci pneumonia diagnosed by mNGS. The clinical characteristics and prognosis were analyzed. Cox regression was used to identified factors associated with severe cases. RESULTS: A total of 63 patients were confirmed with detected Chlamydia psittaci DNA by mNGS in the bronchoalveolar lavage fluid or blood. A total of 16 (25.4%) patients had severe disease. The overall in-hospital mortality was 4.7% (3/63), with a rate of 18.7% (3/16) in the severe group. 90.4% (57/63) of patients were older than 50 years. 21 (33.3%) patients had poultry/bird exposure. The most common symptoms included fever (100%), cough (63.5%) and fatigue (63.5%). All patients showed lung consolidation (100%) on chest CT, with air bronchograms (96.8%) and pleural effusion (41.3%). In the multivariable Cox regression, the levels of hs-CRP (P = 0.003), creatinine (P = 0.002), and presence of bilateral lung infection (P = 0.003) were independent factors associated with severe pneumonia. CONCLUSION: Psittacosis pneumonia predominantly affects middle-aged and elderly adults. Elevated levels of hs-CRP and creatinine, the presence of bilateral lung involvement associated with progression to severe disease. Psittacosis-induced severe pneumonia is associated with high mortality. CLINICAL TRIAL NUMBER: Not applicable.},
	doi = {10.1186/s12879-026-12822-9},
	pmid = {41680679 [Indexed for MEDLINE]},
	note = {PMC12997740}
}

@ARTICLE{10.1007/s10096-026-05404-9,
	author = {Yao Y and Lai Y and Wu Q and Xu W},
	title = {Targeted next-generation sequencing improves diagnosis and antimicrobial stewardship in Chlamydia psittaci pneumonia.},
	journal = {Eur J Clin Microbiol Infect Dis},
	year = {2026},
	abstract = {PURPOSE : Chlamydia psittaci pneumonia (CPP) remains underdiagnosed due to nonspecific clinical manifestations. This study assessed the clinical utility of targeted next-generation sequencing (tNGS) in optimizing CPP diagnosis and antimicrobial stewardship, with a focus on empirical quinolone efficacy. METHODS: We conducted a retrospective cohort study of 35 CPP patients (November 2022-October 2023) diagnosed by tNGS of respiratory specimens (8 sputum/27 bronchoalveolar lavage fluid [BALF]). Data included epidemiological history, laboratory findings, imaging features, therapeutic interventions, and clinical outcomes. Statistical comparisons between severe and non-severe CPP were performed using Student's t-test and Mann-Whitney U tests. RESULTS: Median diagnostic delay post-admission was 4 days (IQR:3-5). Fever predominated as initial presentation (97.1%), with 45.7% reporting avian contact. Leukocyte counts were normal/mildly elevated,, yet neutrophil ratio (83.86 ± 6.17%) and D-dimer (1.31 ± 0.86 mg/L) were notably increased. All patients showed elevated CRP (175.52 ± 87.62 mg/L) and ESR (70.00 ± 22.62 mm/h). Severe CPP cases (n = 8) exhibited higher CRP (p = 0.041) and procalcitonin (p = 0.013) than non-severe cases. Common comorbidities included hepatic dysfunction (68.6%) and pleural effusion (34.3%). Polymicrobial co-infections occurred more frequently in severe CPP cases than in non-severe cases (OR = 21.07, 95% CI:1.11-402.30). tNGS-guided diagnosis prompted antibiotic adjustment in 60.0% of patients (21/35) to targeted quinolone, tetracycline, or combination therapy. Clinical recovery was achieved in 97.1%, with 2.9% mortality. CONCLUSIONS: tNGS enhances early CPP diagnosis and targeted antimicrobial adjustment. Quinolones demonstrate high efficacy as empirical treatment. The strong association between severe CPP and polymicrobial co-infections necessitates comprehensive pathogen screening. Study limitations include a single-center design and a small sample size, warranting validation through prospective multicenter studies.},
	doi = {10.1007/s10096-026-05404-9},
	pmid = {41678126}
}

@ARTICLE{10.3389/fmed.2026.1744125,
	author = {Song Y and Feng R and Sun L and Yan M and Zhou J and Qu C and Huang L},
	title = {Clinical characterization of Chlamydia psittaci infections detected by targeted next generation sequencing in a Chinese tertiary hospital.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {BACKGROUND: Psittacosis is a zoonotic disease caused by Chlamydia psittaci (C. psittaci). Its clinical symptoms are nonspecific, ranging from influenza-like symptoms to severe pneumonia. Thus, it is often ignored and underreported. To date, the report of C. psittaci infections detected by targeted next generation sequencing (tNGS) is still limited. METHODS: tNGS was performed on the platform of Vision Medicals in patients with fever or respiratory infections from August 2024 to August 2025 in our hospital. The specimens included blood and bronchoalveolar lavage fluid (BALF). C. psittaci infection was confirmed by real-time PCR. Detailed clinical data of the included patients were collected and analyzed from electronic medical records. RESULTS: Eight psittacosis patients were detected by tNGS and confirmed by real-time PCR. The median age of 8 patients was 69 years (range: 46-86 years). Five patients (62.5%) had a history of exposure to birds. Clinical symptoms included fever, cough, fatigue, headache and dyspnea. Patients exhibited normal or elevated white blood cell (WBC) counts with decreased lymphocyte counts. C-reactive protein (CRP), procalcitonin (PCT), and interleukin-6 (IL-6) levels were significantly elevated. The majority of patients (87.5%, 7/8) developed hepatic dysfunction. Pulmonary lesions were multi-lobar, presenting as consolidation, ground glass opacities and air bronchogram signs, with pleural effusion occurred in some cases. Following confirmation of C. psittaci infection, targeted antimicrobial therapies with tetracyclines (tigecycline or omacycline) were administered. All patients demonstrated significant reductions in inflammatory markers after treatments, with clinical symptoms improving until resolution. Follow-up chest computed tomography (CT) scans showed resolution of infection foci. All patients ultimately recovered and were discharged. CONCLUSION: tNGS is a promising tool for rapidly detecting C. psittaci infections. Early diagnosis of psittacosis with subsequently targeted therapies improved patients' outcome.},
	doi = {10.3389/fmed.2026.1744125},
	pmid = {41669346},
	note = {PMC12884321}
}

@ARTICLE{10.3389/fcimb.2026.1647511,
	author = {Ni H and Zhu J and Chen Y and Zheng Y and Chen B and Dong C and Zhang S and Xu Y and Jiang Y},
	title = {Clinical characteristics and prognostic impact of streptococcal colonization in critically ill patients with severe pneumonia.},
	journal = {Front Cell Infect Microbiol},
	year = {2026},
	abstract = {BACKGROUND: Streptococcus species are predominant ​commensal residents of the respiratory tract​ in healthy individuals and contribute to immune and metabolic regulation. However, the association between streptococcal colonization and clinical outcomes in patients with severe pneumonia remains undercharacterized. This study aimed to explore the clinical characteristics and the impact of streptococcal colonization on the prognosis of critically ill patients with pneumonia. METHOD: We conducted a multicenter, retrospective, observational cohort study of critically ill pneumonia patients admitted to 12 intensive care units (ICUs) between January 2019 and December 2023 who underwent metagenomic next-generation sequencing (mNGS). Patients were stratified into Streptococcus-colonized and non-colonized groups based on bronchoalveolar lavage fluid (BALF) mNGS results, conventional microbiological testing (CMT), and clinical assessments. Propensity score matching (PSM) was utilized to minimize baseline confounding variables. Using nearest-neighbor matching at a 1:2 ratio, baseline characteristics were balanced between groups post-matching. The primary endpoint was 28-day all-cause mortality. RESULTS: A total of 1,897 patients were enrolled in this study. Among them, 21 patients under 18 years of age, 139 patients lost to follow-up within 28 days, and 4 patients with confirmed streptococcal infection were excluded. Finally, 1,733 patients met the inclusion criteria. The cohort had a mean age of 65 years, with the majority being males (1,213/1,733, 70%). Among these, 148 (8.5%) were classified as Streptococcus-colonized, and 1,585 (91.5%) were Streptococcus-colonization-negative. No significant difference in 28-day all-cause mortality was observed between the colonized and non-colonized groups (35.81% vs. 38.51%, p=0.578). Patients with Streptococcus colonization had a significantly shorter median length of stay (LOS) (17 days, interquartile range [IQR] 11-30) than those without colonization (22 days, IQR 12-33; P = 0.044). Similarly, their median intensive care unit (ICU) LOS (11 days, IQR 7-16) was also significantly shorter than that of non-colonized patients (14 days, IQR 8-25; P = 0.003). Multivariable Cox regression analysis further demonstrated that Streptococcus colonization was not an independent risk factor for 28-day mortality (HR = 1.10, 95% CI: 0.79-1.51, p=0.579). CONCLUSION: Our findings suggest a potential role for Streptococcus colonization in improving clinical outcomes in severe pneumonia. The presence or absence of Streptococcus colonization may influence short-term prognostic benefits in critically ill pneumonia patients. Further research is needed to clarify the clinical significance and potential mechanisms of Streptococcus colonization.},
	doi = {10.3389/fcimb.2026.1647511},
	pmid = {41660425 [Indexed for MEDLINE]},
	note = {PMC12872922}
}

@ARTICLE{10.3389/fcimb.2025.1688473,
	author = {Xu Y and Ma Y and Huang Q and Guo X and Guo L and Ren Y and Lu W and Wu X and Li D and Li S},
	title = {The role of bronchoalveolar lavage fluid metagenomic next-generation sequencing in detecting pathogens and optimising antibiotic therapy in paediatric severe community-acquired pneumonia.},
	journal = {Front Cell Infect Microbiol},
	year = {2026},
	abstract = {BACKGROUND: Severe community-acquired pneumonia (SCAP) remains a major cause of mortality in the paediatric population, with current diagnostic and treatment approaches often proving insufficient and contributing to the growing challenge of antibiotic resistance. This study explored the potential of metagenomic next-generation sequencing (mNGS) of bronchoalveolar lavage fluid as a tool to enhance the precision of antibiotic management in children with SCAP. METHODS: A retrospective cohort study of 202 paediatric patients with community-acquired pneumonia (aged 1 month-18 years) admitted to the First Affiliated Hospital of Xinxiang Medical University (November 2020-March 2023) was conducted. Patients were grouped by severity (intensive care unit [ICU]/non-ICU) and mNGS timing (early: ≤72 hours post-admission; late: >72 hours). The diagnostic efficacy of mNGS versus conventional microbiological techniques (CMT) was evaluated using sensitivity, specificity, positive/negative predictive values and area under the receiver operating characteristic curve (AUC) analysis. Antibiotic adjustments and clinical outcomes were analysed via survival statistics. RESULTS: Metagenomic next-generation sequencing showed a higher positive detection rate (98.51%) than CMT (47.52%) (AUC = 0.82, 95%CI: 0.76-0.88). Of the 202 patients, 127 (62.87%) were male, with a median age of 1.88 years (interquartile range: 0.29-7 years). Early mNGS was associated with fewer extrapulmonary complications (69.63% vs 55.22% in the late group, p < 0.05), and shorter hospitalisation (median 13 vs 15 days, p <0.01). Antibiotic escalation occurred in 50 (24.75%) cases, de-escalation in 22 (10.89%) and same-level adjustment in 25 (12.38%). CONCLUSION: Metagenomic next-generation sequencing outperforms CMT in pathogen detection. Early mNGS is associated with improved clinical outcomes, suggesting its potential utility in paediatric SCAP management.},
	doi = {10.3389/fcimb.2025.1688473},
	pmid = {41613591 [Indexed for MEDLINE]},
	note = {PMC12847449}
}

@ARTICLE{10.1186/s40001-026-03892-1,
	author = {Wang Y and Shen Y and Shen J and Bi J and Xu J and Wei T and Wang R and Wu X and Li F and Bai J and Jie Z and Hou D and Song Y},
	title = {Airway microbiome dysbiosis in severe pneumonia: metagenomic evidence of pathogen expansion and commensal depletion.},
	journal = {Eur J Med Res},
	year = {2026},
	abstract = {BACKGROUND: The pulmonary microbiome is increasingly recognized as a key determinant of pneumonia severity, yet its clinical implications remain incompletely understood. Disruption of microbial ecology, or dysbiosis, may impair host immune responses and exacerbate disease progression. This study aimed to characterize microbiome alterations associated with severe pneumonia and their correlation with host inflammatory and coagulative parameters. METHODS: In this multicenter, prospective observational cohort study conducted across nine hospitals in Shanghai (2021-2025), bronchoalveolar lavage fluid (BALF) samples from 306 patients with clinically diagnosed pulmonary infections were analyzed using metagenomic next-generation sequencing (mNGS). Patients were stratified into severe (n = 196) and non-severe (n = 110) groups using WHO-derived severe pneumonia criteria at the time of bronchoalveolar lavage (BAL). Microbial taxonomic profiles, diversity indices, co-occurrence networks, and correlations with clinical markers were comprehensively assessed using standard bioinformatic and statistical approaches. RESULTS: Severe pneumonia was associated with marked microbial dysbiosis, including reorganization of co-occurrence network topology with centrality shifting away from commensals toward opportunistic taxa in severe disease, characterized by reduced α-diversity, altered β-diversity, and enrichment of opportunistic Gram-negative pathogens including Acinetobacter and Klebsiella. In contrast, commensals such as Rothia and Prevotella were depleted. Co-occurrence network analysis revealed fragmentation of microbial interactions in severe cases, with centrality shifting from commensals to opportunists like Corynebacterium striatum. Shannon diversity negatively correlated with SOFA scores, and specific taxa positively associated with systemic inflammation (CRP, PCT) and coagulation abnormalities. Nearly all samples demonstrated polymicrobial infection, with distinct microbial patterns observed across monomicrobial and polymicrobial subgroups. CONCLUSION: Our multicenter observational analysis suggests that severe pneumonia is associated with marked ecological disruption of the lower-airway microbiome, characterized by commensal loss, opportunist expansion, and fragmented interspecies networks, and with concurrent inflammatory and coagulative abnormalities. These hypothesis-generating findings warrant external validation in independent, multi-region cohorts and longitudinal sampling to test directionality and causality before informing clinical decision-making.},
	doi = {10.1186/s40001-026-03892-1},
	pmid = {41612472 [Indexed for MEDLINE]},
	note = {PMC12924258}
}

@ARTICLE{10.1186/s12890-026-04131-3,
	author = {Zhang X and Xu J and Chen M and Wu Y and Chen D and Xu X and He X},
	title = {Aspergillus fumigatus in mechanically ventilated pneumonia- independent mortality risk and synergistic microbiome signatures from a multicenter mNGS cohort.},
	journal = {BMC Pulm Med},
	year = {2026},
	abstract = {AIM OF THE STUDY: Invasive aspergillosis is a life-threatening complication in mechanically ventilated patients with pneumonia, predominantly caused by Aspergillus fumigatus. However, its independent mortality risk and early-warning strategies in critically ill populations remain unclear. METHODS: In this multicenter retrospective cohort study, we enrolled 1567 mechanically ventilated patients with severe pneumonia who underwent bronchoalveolar lavage fluid (BALF) metagenomic next-generation sequencing (mNGS) across 12 tertiary hospitals in China (January 2019–March 2023). Propensity score matching (1:1) balanced confounders, and Cox regression quantified the independent mortality risk of A. fumigatus infection. RESULTS: The A. fumigatus detection rate was 10.27% (161/1567). Post-matching, 28-day mortality was significantly higher in A. fumigatus-positive versus negative cohorts (66% vs 47%, p = 0.001). Multivariable analysis confirmed A. fumigatus as an independent mortality risk factor (HR = 1.79, 95%CI 1.49–2.17, p < 0.001), with significant associations to underlying renal disease (19% vs 12%, p = 0.005), connective tissue disease (7% vs 4%, p = 0.026), and multi-organ dysfunction (ep < 0.05). Microbial community analysis revealed co-colonization synergies with Enterococcus faecium, Enterococcus faecalis, Candida albicans, HSV-1, and EBV. CONCLUSIONS: A. fumigatus infection independently increases 28-day mortality risk in mechanically ventilated patients. Early intensified screening and intervention are warranted for individuals with ≥ 3 organ dysfunctions, underlying renal/connective tissue diseases, or respiratory co-colonization by synergistic microbes. SUPPLEMENTARY INFORMATION: The online version contains supplementary material available at 10.1186/s12890-026-04131-3.},
	doi = {10.1186/s12890-026-04131-3},
	pmid = {41606550},
	note = {PMC12924287}
}

@ARTICLE{10.1186/s12941-026-00848-5,
	author = {Sun Y and Guo K and Tang J and Zhao J and Zhang X and Yan Y and Yuan L and Zhang Y and Qiu C and Luo J and Chen J and Fang H},
	title = {The impact of the timing of mNGS-guided antibiotic adjustment on clinical outcomes in ICU patients with severe community-acquired pneumonia: a retrospective study.},
	journal = {Ann Clin Microbiol Antimicrob},
	year = {2026},
	abstract = {BACKGROUND: Severe community-acquired pneumonia (SCAP) remains a major cause of intensive care unit (ICU) admission and mortality. Prompt pathogen identification and timely administration of appropriate antimicrobial therapy are essential for improving patient outcomes. Although metagenomic next-generation sequencing (mNGS) enables rapid pathogen detection, the prognostic impact of the timing of mNGS-guided antibiotic adjustment remains unclear. METHODS: We conducted a multicenter retrospective study of ICU patients diagnosed with SCAP who underwent both bronchoalveolar lavage fluid (BALF) mNGS and conventional microbiological tests (CMTs). Patients were categorized into early (≤ 72 h) and late (> 72 h) antibiotic adjustment groups based on the interval from ICU admission to the time of antibiotic adjustment guided by mNGS results. Subgroup analyses were performed according to immune status. RESULTS: In our study, mNGS significantly outperformed conventional microbiological tests (CMTs) in pathogen detection (92.70% vs. 57.18%, P < 0.001), with a particularly higher yield for mixed infections (51.63% vs. 19.14%, P < 0.001). Early mNGS-guided antibiotic adjustment was associated with a significantly reduced 28-day mortality compared to late adjustment (41.98% vs. 53.76%, P = 0.037). Furthermore, multivariate logistic regression analysis confirmed early adjustment as an independent protective factor for 28-day mortality (adjusted OR = 0.44, 95% CI: 0.23-0.83, P = 0.011). In the immunocompromised subgroup, early mNGS-guided adjustment was associated with significantly lower 28-day mortality than late adjustment (39.29% vs. 60.00%, P = 0.029), with a significant interaction observed between timing and immune status (P = 0.042). CONCLUSION: Early mNGS-guided antibiotic adjustment is associated with improved survival among ICU patients with SCAP. This benefit is more pronounced in immunocompromised patients, underscoring the importance of early mNGS application to guide antimicrobial decision-making in this vulnerable population.},
	doi = {10.1186/s12941-026-00848-5},
	pmid = {41549319 [Indexed for MEDLINE]},
	note = {PMC12895937}
}

@ARTICLE{10.1186/s40001-026-03893-0,
	author = {Xiao Y and Tang Y and Yan Y and Cheng Q and Chen X and Wang L and Li X},
	title = {Targeted next-generation sequencing has comparable clinical value to metagenomic NGS for pulmonary infections in hematological malignancy patients: a real-world propensity score-matched study.},
	journal = {Eur J Med Res},
	year = {2026},
	abstract = {BACKGROUND: Metagenomic next-generation sequencing (mNGS) is widely recognized in immunocompromised populations due to its unbiased ability to identify pathogens, while targeted next-generation sequencing (tNGS) combines PCR amplification with high-throughput sequencing technology, with advantages of lower costs and shorter turnaround times. However, it remains unclear whether tNGS can be applied in the same way as mNGS for immunodeficient patients with hematologic malignances (HM). METHODS: This retrospective study analyzed clinical data from 245 HM patients suspected of pneumonia between April 2019 and April 2024. Bronchoalveolar lavage fluid (BALF) samples were tested using either tNGS or mNGS. Propensity score matching (PSM) (1:1) balanced the groups. RESULTS: tNGS and mNGS showed comparable sensitivity, specificity, and accuracy for pathogen detection (97.3% vs 94.2%, 26.3% vs 26.1%, 82.6% vs 77.2%; all P > 0.05), with similar accuracy across immunodeficiency states (severe immunodeficiency: 80.0% vs 81.8%; non-severe immunodeficiency: 64.7% vs 86.7%; both P > 0.05). For non-severe pneumonia, tNGS was comparable to mNGS (accuracy: 77.9% vs 86.3%, P > 0.05), but mNGS was significantly superior in severe cases (accuracy: 50.0% vs 100.0%, P = 0.002). Both groups improved rate of correct antibiotic use (tNGS: 50.9% to 84.3%; mNGS: 57.1% to 77.8%, P < 0.01) and reduced overuse rates (tNGS: 25.9% to 2.8%; mNGS: 4.8% to 25.4%; P < 0.01), with no difference in chemotherapy intervals (37.5 ± 22.9 days vs 41.0 ± 38.4 days; P = 0.89). CONCLUSION: In HM patients suspected of pulmonary infection, BALF-tNGS showed comparable diagnostic efficacy as BALF-mNGS, with similar clinical value across varying immunodeficiency states. tNGS is a viable alternative for non-severe pneumonia, while mNGS is superior in severe cases. Collectively, the findings of this study highlight tNGS as an alternative diagnostic approach for HM patients.},
	doi = {10.1186/s40001-026-03893-0},
	pmid = {41547817}
}

@ARTICLE{10.3389/fcimb.2025.1742311,
	author = {Wang S and Yu Y and Lihe C and Sun L and Du N and Minglei Z},
	title = {CD4(+) T cells stratification unveils a dynamic pathogen landscape in severe pneumonia: a targeted next-generation sequencing-based cohort study.},
	journal = {Front Cell Infect Microbiol},
	year = {2025},
	abstract = {BACKGROUND: The host's immune status is a critical determinant of the pathogen profile in pulmonary infections, but quantitative indicators to delineate this dynamic association are lacking. This study aimed to use CD4+ T cells count as an objective parameter to systematically characterize the evolution of the pathogen profile in bronchoalveolar lavage fluid-targeted next-generation sequencing (BALF-tNGS) from patients with severe pneumonia. METHODS: We retrospectively analyzed 286 adult patients who underwent BALF-tNGS for severe pneumonia. Patients were stratified into four strata based on CD4+ T cells count: severe immunosuppression, moderate immunosuppression, low-normal immunity, and immunocompetent. Cochran-Armitage trend test, cluster analysis, and Kruskal-Wallis test were used to analyze the associations between CD4+ T cells strata and pathogen detection rates/co-infection complexity. RESULTS: The detection rates of Pneumocystis jirovecii (PJP) and Cytomegalovirus (CMV) showed a highly significant increasing trend with decreasing CD4+ T cells strata (p < 0.05). CD4+ T cells count < 100 cells/μL was the most significant risk factor for PJP infection (detection rate 39.6%). Meanwhile, as the CD4+ T cells count decreased, the number of pathogen species detected in the patient's BALF significantly increased, with a statistically significant difference between groups (p < 0.05). The median number in the severe immunosuppression stratum was significantly higher than that in the immunocompetent stratum. CONCLUSION: The CD4+ T cells count quantitatively defines the pathogen ecology in pulmonary infections. A CD4+ T cells count < 100 cells/μL represents a critical threshold for opportunistic infections and complex co-infections. These findings support the integration of CD4+ T cells counting into the initial assessment framework for severe pneumonia to guide precise empirical therapy and diagnostic strategies.},
	doi = {10.3389/fcimb.2025.1742311},
	pmid = {41488483 [Indexed for MEDLINE]},
	note = {PMC12756350}
}
